import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Calendar, Clock, X, CheckCircle, AlertCircle } from 'lucide-react';
import api from '../lib/api';

const AppointmentBooking = ({ camp, onClose, onSuccess }) => {
    const [step, setStep] = useState(1); // 1: Select Date, 2: Select Time, 3: Confirm
    const [selectedDate, setSelectedDate] = useState(null);
    const [selectedTime, setSelectedTime] = useState(null);
    const [availableSlots, setAvailableSlots] = useState([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [success, setSuccess] = useState(false);

    useEffect(() => {
        if (step === 2 && selectedDate) {
            fetchAvailableSlots();
        }
    }, [step, selectedDate, fetchAvailableSlots]);

    const fetchAvailableSlots = useCallback(async () => {
        try {
            setLoading(true);
            setError(null);
            console.log('Fetching slots for camp:', camp);
            
            if (!camp || !camp.id) {
                throw new Error('Invalid camp data');
            }
            
            const response = await api.get(`/appointments/camps/${camp.id}/slots`);
            console.log('Slots response:', response.data);
            
            if (response.data.status === 'success') {
                setAvailableSlots(response.data.data);
            } else {
                throw new Error(response.data.message || 'Failed to fetch slots');
            }
        } catch (err) {
            console.error('Fetch slots error:', err);
            setError(err.response?.data?.message || err.message || 'Failed to fetch available slots');
        } finally {
            setLoading(false);
        }
    }, [camp]);

    const handleBookAppointment = async () => {
        try {
            setLoading(true);
            setError(null);
            
            const token = localStorage.getItem('token');
            if (!token) {
                throw new Error('Please log in to book an appointment');
            }
            
            console.log('Booking appointment:', { campId: camp.id, timeSlot: selectedTime });
            
            const response = await api.post(
                '/appointments/book',
                {
                    campId: camp.id,
                    timeSlot: selectedTime,
                    bloodGroup: localStorage.getItem('userBloodGroup'),
                    age: localStorage.getItem('userAge')
                }
            );

            console.log('Booking response:', response.data);

            if (response.data.status === 'success') {
                setSuccess(true);
                setTimeout(() => {
                    onSuccess?.();
                    onClose();
                }, 2000);
            } else {
                throw new Error(response.data.message || 'Booking failed');
            }
        } catch (err) {
            console.error('Booking error:', err);
            setError(err.response?.data?.message || err.message || 'Failed to book appointment');
        } finally {
            setLoading(false);
        }
    };

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/50 backdrop-blur-sm z-[9999] flex items-center justify-center p-4"
            onClick={onClose}
        >
            <motion.div
                initial={{ scale: 0.95, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                exit={{ scale: 0.95, opacity: 0 }}
                onClick={e => e.stopPropagation()}
                className="bg-white rounded-2xl shadow-2xl max-w-md w-full p-6"
            >
                {/* Header */}
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-2xl font-black text-gray-900">Request Donation Slot</h2>
                    <button
                        onClick={onClose}
                        className="text-gray-400 hover:text-gray-600 transition-colors"
                    >
                        <X className="w-6 h-6" />
                    </button>
                </div>

                {/* Camp Info */}
                <div className="bg-red-50 rounded-xl p-4 mb-4">
                    <p className="text-sm font-bold text-gray-900">{camp?.name || 'Unknown Camp'}</p>
                    <p className="text-xs text-gray-600 mt-1">{camp?.address || 'No address'}</p>
                    {!camp?.id && (
                        <p className="text-xs text-red-600 mt-1">ΓÜá∩╕Å Invalid camp data</p>
                    )}
                </div>

                {/* Admin Approval Notice */}
                <div className="bg-blue-50 border border-blue-200 rounded-lg p-3 mb-6">
                    <div className="flex gap-2">
                        <AlertCircle className="w-4 h-4 text-blue-600 flex-shrink-0 mt-0.5" />
                        <div>
                            <p className="text-sm font-medium text-blue-900">Admin Approval Required</p>
                            <p className="text-xs text-blue-700 mt-1">
                                Your donation request will be reviewed by our admin team. You'll receive a notification once approved.
                            </p>
                        </div>
                    </div>
                </div>

                {/* Success State */}
                {success && (
                    <motion.div
                        initial={{ scale: 0 }}
                        animate={{ scale: 1 }}
                        className="text-center py-8"
                    >
                        <CheckCircle className="w-16 h-16 text-green-500 mx-auto mb-4" />
                        <h3 className="text-lg font-bold text-gray-900 mb-2">Request Submitted!</h3>
                        <p className="text-sm text-gray-600">Your donation request has been sent for admin approval. You'll be notified once approved.</p>
                    </motion.div>
                )}

                {/* Error State */}
                {error && !success && (
                    <div className="bg-red-50 border border-red-200 rounded-lg p-3 mb-4 flex gap-3">
                        <AlertCircle className="w-5 h-5 text-red-600 flex-shrink-0 mt-0.5" />
                        <p className="text-sm text-red-700">{error}</p>
                    </div>
                )}

                {!success && (
                    <>
                        {/* Step 1: Select Date */}
                        {step === 1 && (
                            <div>
                                <label className="block text-sm font-bold text-gray-900 mb-3">Select Date</label>
                                <div className="space-y-2 mb-6">
                                    {[0, 1, 2, 3, 4].map(i => {
                                        const d = new Date(camp.date);
                                        const isValid = camp.date && !isNaN(d.getTime());
                                        if (isValid) d.setDate(d.getDate() + i);
                                        
                                        const dateStr = isValid ? d.toISOString().split('T')[0] : `pending-${i}`;
                                        const isSelected = selectedDate === dateStr;

                                        return (
                                            <button
                                                key={i}
                                                onClick={() => setSelectedDate(dateStr)}
                                                className={`w-full p-3 rounded-lg border-2 transition-all text-left ${
                                                    isSelected
                                                        ? 'border-red-500 bg-red-50'
                                                        : 'border-gray-200 hover:border-red-200'
                                                }`}
                                            >
                                                <div className="flex items-center gap-2">
                                                    <Calendar className="w-4 h-4" />
                                                    <span className="font-medium text-gray-900">
                                                        {isValid ? d.toLocaleDateString('en-US', {
                                                            weekday: 'short',
                                                            month: 'short',
                                                            day: 'numeric'
                                                        }) : 'Date TBA'}
                                                    </span>
                                                </div>
                                            </button>
                                        );
                                    })}
                                </div>
                                <button
                                    onClick={() => setStep(2)}
                                    disabled={!selectedDate}
                                    className="w-full bg-red-600 hover:bg-red-700 disabled:bg-gray-300 text-white font-bold py-3 rounded-lg transition-colors"
                                >
                                    Continue
                                </button>
                            </div>
                        )}

                        {/* Step 2: Select Time */}
                        {step === 2 && (
                            <div>
                                <label className="block text-sm font-bold text-gray-900 mb-3">Select Time Slot</label>
                                {loading ? (
                                    <div className="text-center py-8">
                                        <div className="inline-block animate-spin">
                                            <Clock className="w-6 h-6 text-red-600" />
                                        </div>
                                        <p className="text-sm text-gray-600 mt-2">Loading available slots...</p>
                                    </div>
                                ) : (
                                    <>
                                        <div className="grid grid-cols-2 gap-2 mb-6 max-h-64 overflow-y-auto">
                                            {availableSlots.map(slot => (
                                                <button
                                                    key={slot.time}
                                                    onClick={() => setSelectedTime(slot.time)}
                                                    disabled={!slot.available}
                                                    className={`p-2 rounded-lg border-2 transition-all text-sm font-medium ${
                                                        selectedTime === slot.time
                                                            ? 'border-red-500 bg-red-50 text-red-700'
                                                            : slot.available
                                                            ? 'border-gray-200 text-gray-700 hover:border-red-200'
                                                            : 'border-gray-100 text-gray-400 bg-gray-50 cursor-not-allowed'
                                                    }`}
                                                >
                                                    {slot.time}
                                                </button>
                                            ))}
                                        </div>
                                        <div className="flex gap-3">
                                            <button
                                                onClick={() => setStep(1)}
                                                className="flex-1 border-2 border-gray-200 text-gray-700 font-bold py-3 rounded-lg hover:bg-gray-50 transition-colors"
                                            >
                                                Back
                                            </button>
                                            <button
                                                onClick={() => setStep(3)}
                                                disabled={!selectedTime}
                                                className="flex-1 bg-red-600 hover:bg-red-700 disabled:bg-gray-300 text-white font-bold py-3 rounded-lg transition-colors"
                                            >
                                                Continue
                                            </button>
                                        </div>
                                    </>
                                )}
                            </div>
                        )}

                        {/* Step 3: Confirm */}
                        {step === 3 && (
                            <div>
                                <div className="bg-gray-50 rounded-lg p-4 mb-6 space-y-3">
                                    <div>
                                        <p className="text-xs text-gray-600 font-medium">CAMP</p>
                                        <p className="text-sm font-bold text-gray-900">{camp.name}</p>
                                    </div>
                                    <div>
                                        <p className="text-xs text-gray-600 font-medium">DATE</p>
                                        <p className="text-sm font-bold text-gray-900">
                                            {(() => {
                                                const d = new Date(selectedDate);
                                                return (selectedDate && !isNaN(d.getTime())) ? d.toLocaleDateString('en-US', {
                                                    weekday: 'long',
                                                    month: 'long',
                                                    day: 'numeric'
                                                }) : 'TBA';
                                            })()}
                                        </p>
                                    </div>
                                    <div>
                                        <p className="text-xs text-gray-600 font-medium">TIME SLOT</p>
                                        <p className="text-sm font-bold text-gray-900">{selectedTime}</p>
                                    </div>
                                </div>

                                <div className="flex gap-3">
                                    <button
                                        onClick={() => setStep(2)}
                                        className="flex-1 border-2 border-gray-200 text-gray-700 font-bold py-3 rounded-lg hover:bg-gray-50 transition-colors"
                                    >
                                        Back
                                    </button>
                                    <button
                                        onClick={handleBookAppointment}
                                        disabled={loading}
                                        className="flex-1 bg-red-600 hover:bg-red-700 disabled:bg-gray-300 text-white font-bold py-3 rounded-lg transition-colors"
                                    >
                                        {loading ? 'Submitting...' : 'Submit Request'}
                                    </button>
                                </div>
                            </div>
                        )}
                    </>
                )}
            </motion.div>
        </motion.div>
    );
};

export default AppointmentBooking;

import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { Menu, X, HeartPulse, LogOut, User, Sun, Moon } from 'lucide-react';
import { AnimatePresence } from 'framer-motion';
import { useAuthStore } from '../context/authStore';
import { useThemeStore } from '../context/themeStore';

const Navbar = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();
  const { isAuthenticated, user, logout } = useAuthStore();
  const { isDark, toggleTheme } = useThemeStore();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close mobile menu on route change
  useEffect(() => {
    if (isMobileMenuOpen) setIsMobileMenuOpen(false);
  }, [location.pathname, isMobileMenuOpen]);

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'Donation Camps', path: '/camps' },
    { name: 'Heroes', path: '/heroes' },
    { name: 'Compatibility', path: '/compatibility' },
  ];

  if (isAuthenticated) {
    if (user?.role === 'ADMIN') {
      navLinks.push({ name: 'Admin Panel', path: '/admin-dashboard' });
    } else if (user?.role === 'ORGANIZATION') {
      navLinks.push({ name: 'Create Camp', path: '/org-dashboard' });
    } else {
      navLinks.push({ name: 'My Dashboard', path: '/dashboard' });
    }
  }

  const handleLogout = () => {
      logout();
      navigate('/login');
  };

  return (
    <nav
      className={`fixed w-full z-[999] transition-all duration-300 ${
        isScrolled ? 'bg-white bg-opacity-95 shadow-lg py-2 backdrop-blur-md border-b border-gray-100' : 'bg-white bg-opacity-70 py-4 glass'
      }`}
    >
      <div className="container mx-auto px-6 flex justify-between items-center">
        <Link to="/" className="text-3xl font-bold text-red-600 tracking-tighter flex items-center gap-2 brand-font transform transition hover:scale-105">
          {/* <motion.div animate={{ scale: [1, 1.2, 1] }} transition={{ repeat: Infinity, duration: 2 }}>
            <HeartPulse className="text-red-500 w-8 h-8" />
          </motion.div> */}
          LifeFlow
        </Link>

        {/* Desktop Navigation */}
        <div className="hidden md:flex space-x-8 text-sm uppercase tracking-wider font-semibold items-center">
          {navLinks.map((link) => (
            <Link
              key={link.path}
              to={link.path}
              className={`transition-colors relative group ${
                location.pathname === link.path ? 'text-red-600' : 'text-gray-700 hover:text-red-600'
              }`}
            >
              {link.name}
              <span className={`absolute -bottom-1 left-0 w-0 h-0.5 bg-red-600 transition-all group-hover:w-full ${location.pathname === link.path ? 'w-full' : ''}`}></span>
            </Link>
          ))}

          {isAuthenticated ? (
            <div className="flex items-center gap-4 border-l border-gray-200 pl-4">
              <span className="text-gray-900 font-bold brand-font mr-2">Hi, {user?.name?.split(' ')[0].toUpperCase()}</span>
              <Link to={user?.role === 'ADMIN' ? '/admin-dashboard' : user?.role === 'ORGANIZATION' ? '/org-dashboard' : '/dashboard'} className="text-gray-600 hover:text-gray-900 transition-colors">
                <User className="w-5 h-5" />
              </Link>
              <button onClick={toggleTheme} className="text-gray-600 hover:text-gray-900 transition-colors" title="Toggle dark mode">
                {isDark ? <Sun className="w-5 h-5 text-yellow-500" /> : <Moon className="w-5 h-5" />}
              </button>
              <button onClick={handleLogout} className="bg-gray-900 text-white px-5 py-2.5 rounded-full hover:bg-black transition-all shadow-md hover:shadow-lg text-sm flex items-center gap-2 font-bold">
                <LogOut className="w-4 h-4" /> Logout
              </button>
            </div>
          ) : (
            <div className="flex items-center gap-4">
              <button onClick={toggleTheme} className="text-gray-600 hover:text-gray-900 transition-colors" title="Toggle dark mode">
                {isDark ? <Sun className="w-5 h-5 text-yellow-500" /> : <Moon className="w-5 h-5" />}
              </button>
              <Link to="/login" className="text-gray-700 hover:text-red-600 transition-colors">
                Login
              </Link>
              <Link to="/register" className="bg-red-600 text-white px-6 py-2.5 rounded-full hover:bg-red-700 transition-all shadow-md hover:shadow-lg hover:-translate-y-0.5 font-bold">
                Register
              </Link>
            </div>
          )}
        </div>

        {/* Mobile Menu Button */}
        <button
          className="md:hidden text-gray-700 hover:text-red-600 focus:outline-none transition-transform active:scale-95"
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
          {isMobileMenuOpen ? <X className="w-7 h-7" /> : <Menu className="w-7 h-7" />}
        </button>
      </div>

      {/* Mobile Navigation Drawer */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            transition={{ duration: 0.2 }}
            className="md:hidden absolute top-full left-0 w-full bg-white/95 backdrop-blur-xl border-t border-gray-100 shadow-xl"
          >
            <div className="container mx-auto px-6 py-4 flex flex-col space-y-4 font-bold text-center">
              {navLinks.map((link) => (
                <Link
                  key={link.path}
                  to={link.path}
                  className={`py-2 ${location.pathname === link.path ? 'text-red-600' : 'text-gray-700 hover:text-red-600'}`}
                >
                  {link.name}
                </Link>
              ))}

              <div className="border-t border-gray-100 pt-4 flex flex-col gap-4">
                {isAuthenticated ? (
                  <>
                    <span className="text-gray-900 font-bold brand-font py-2">Hi, {user?.name}</span>
                    <Link to={user?.role === 'ADMIN' ? '/admin-dashboard' : user?.role === 'ORGANIZATION' ? '/org-dashboard' : '/dashboard'} className="text-gray-700 hover:text-red-600 py-2">
                        {user?.role === 'ADMIN' ? 'Admin Panel' : 'My Dashboard'}
                    </Link>
                    <button onClick={handleLogout} className="bg-gray-900 text-white px-6 py-3 rounded-xl mx-auto w-1/2 min-w-[150px] flex items-center justify-center gap-2">
                        <LogOut className="w-4 h-4" /> Logout
                    </button>
                  </>
                ) : (
                  <>
                    <Link to="/login" className="text-gray-700 hover:text-red-600 py-2">Login</Link>
                    <Link to="/register" className="bg-red-600 text-white px-6 py-3 rounded-xl mx-auto w-1/2 min-w-[150px]">Register</Link>
                  </>
                )}
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
};

export default Navbar;

import React, { useState, useEffect, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import {
    Activity, Users, FileText, CheckCircle, XCircle,
    Clock3, MapPin, Building2, Calendar, Trash2, Mail,
    Phone, Droplet, User, HandHeart
} from 'lucide-react';
import api from '../lib/api';
import toast from 'react-hot-toast';

const StatCard = ({ label, value, icon: Icon, color }) => (
    <div className="bg-[var(--bg-secondary)] backdrop-blur-[40px] p-8 rounded-[2.5rem] border border-[var(--border)] shadow-[var(--shadow)] group hover:border-[var(--accent)]/50 transition-all duration-500 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-24 h-24 bg-[var(--accent)]/5 rounded-bl-[100%] z-0 transition-transform group-hover:scale-110"></div>
        <div className="relative z-10">
            <div className={`w-12 h-12 ${color} rounded-2xl flex items-center justify-center mb-6 shadow-xl`}>
                {Icon && <Icon className="w-6 h-6 text-white" />}
            </div>
            <p className="text-[10px] text-[var(--text-muted)] uppercase font-black tracking-[0.2em]">{label}</p>
            <h2 className="text-5xl font-black text-[var(--text-primary)] brand-font mt-2 tracking-tight">{value ?? 'ΓÇô'}</h2>
        </div>
    </div>
);

const AdminDashboard = () => {
    // const { user } = useAuthStore();
    const [activeSection, setActiveSection] = useState('monitor');
    const [stats, setStats] = useState({});
    const [bloodStock, setBloodStock] = useState({});
    const [requests, setRequests] = useState([]);
    const [pendingDonations, setPendingDonations] = useState([]);
    const [pendingCamps, setPendingCamps] = useState([]);
    const [users, setUsers] = useState([]);
    const [orgs, setOrgs] = useState([]);
    const [isLoading, setIsLoading] = useState(false);

    const fetchDashboardData = useCallback(async () => {
        setIsLoading(true);
        try {
            const res = await api.get('/admin/dashboard');
            if (res.data.status === 'success') {
                setStats(res.data.data);
                setBloodStock(res.data.data.stock || {});
            }
        } finally {
            setIsLoading(false);
        }
    }, []);

    const fetchRequests = useCallback(async () => {
        setIsLoading(true);
        try {
            const res = await api.get('/admin/requests/pending');
            if (res.data.status === 'success') setRequests(res.data.data);
        } finally {
            setIsLoading(false);
        }
    }, []);

    const fetchPendingDonations = useCallback(async () => {
        const res = await api.get('/admin/donations/pending');
        if (res.data.status === 'success') setPendingDonations(res.data.data);
    }, []);

    const fetchPendingCamps = useCallback(async () => {
        const res = await api.get('/admin/camps/pending');
        if (res.data.status === 'success') setPendingCamps(res.data.camps);
    }, []);

    const fetchUsers = useCallback(async () => {
        try {
            console.log('Fetching users from /admin/users...');
            const res = await api.get('/admin/users');
            console.log('Users response:', res.data);
            if (res.data.status === 'success') {
                setUsers(res.data.users);
                console.log('Users set in state:', res.data.users);
            } else {
                console.error('Failed to fetch users:', res.data.message);
            }
        } catch (error) {
            console.error('Error fetching users:', error);
            console.error('Error response:', error.response?.data);
        }
    }, []);

    const fetchOrgs = useCallback(async () => {
        const res = await api.get('/admin/organizations');
        if (res.data.status === 'success') setOrgs(res.data.orgs);
    }, []);

    // Global dashboard stats polling (for sidebar badges)
    // Runs on mount and every 30 seconds
    useEffect(() => {
        // Initial fetch inside a timeout to avoid synchronous setState warning
        const timer = setTimeout(() => {
            fetchDashboardData();
        }, 0);

        const interval = setInterval(() => {
            fetchDashboardData();
        }, 30000);

        return () => {
            clearTimeout(timer);
            clearInterval(interval);
        };
    }, [fetchDashboardData]);

    useEffect(() => {
        const loaders = {
            monitor: fetchDashboardData,
            requests: fetchRequests,
            donations: fetchPendingDonations,
            camps: fetchPendingCamps,
            users: fetchUsers,
            organizations: fetchOrgs,
        };
        const load = loaders[activeSection];
        if (load) {
            load().catch(() => toast.error('Failed to load data'));
        }
    }, [activeSection, fetchDashboardData, fetchRequests, fetchPendingDonations, fetchPendingCamps, fetchUsers, fetchOrgs]);

    const handleRequestAction = async (id, status) => {
        try {
            await api.put(`/admin/requests/${id}`, { status });
            toast.success(`Request ${status.toLowerCase()}.`);
            fetchRequests();
            fetchDashboardData(); // Update badges instantly
        } catch { toast.error('Action failed'); }
    };

    const handleDonationAction = async (id, status) => {
        try {
            await api.put(`/admin/donations/${id}`, { status });
            toast.success(`Donation offer ${status.toLowerCase()}.`);
            fetchPendingDonations();
            fetchDashboardData(); // Update badges instantly
        } catch { toast.error('Action failed'); }
    };

    const handleCampAction = async (id, status) => {
        try {
            const note = status === 'REJECTED' ? prompt('Rejection reason (optional):') : null;
            await api.put(`/admin/camps/${id}`, { status, adminNote: note });
            toast.success(`Camp ${status.toLowerCase()}.`);
            fetchPendingCamps();
            fetchDashboardData(); // Update badges instantly
        } catch { toast.error('Action failed'); }
    };

    const handleRemoveUser = async (id, name) => {
        if (!confirm(`Remove "${name}" from LifeFlow? This cannot be undone.`)) return;
        try {
            await api.delete(`/admin/users/${id}`);
            toast.success(`${name} removed.`);
            // Refresh whichever list we're on
            if (activeSection === 'users') fetchUsers();
            else fetchOrgs();
        } catch (err) {
            toast.error(err.response?.data?.message || 'Failed to remove user');
        }
    };

    const tabVars = {
        hidden: { opacity: 0, y: 10 },
        visible: { opacity: 1, y: 0, transition: { duration: 0.3 } },
        exit: { opacity: 0, y: -10, transition: { duration: 0.2 } }
    };

    const navItems = [
        { id: 'monitor', icon: Activity, label: 'Live Monitor' },
