                    </AnimatePresence>
                </div>
            </div>

            {/* Appointment Booking Modal */}
            <AnimatePresence>
                {showBooking && selectedCamp && (
                    <AppointmentBooking
                        camp={selectedCamp}
                        onClose={() => setShowBooking(false)}
                        onSuccess={() => {
                            // Refresh camps or show success message
                            setSelectedCamp(null);
                        }}
                    />
                )}
            </AnimatePresence>
        </motion.div>
    );
};

