import toast from 'react-hot-toast';

const STATUS_STYLES = {
    PENDING: 'bg-yellow-50 text-yellow-700 border-yellow-200',
    APPROVED: 'bg-green-50 text-green-700 border-green-200',
    REJECTED: 'bg-red-50 text-red-700 border-red-200',
};

const STATUS_ICONS = {
    PENDING: <Clock className="w-3.5 h-3.5" />,
    APPROVED: <CheckCircle className="w-3.5 h-3.5" />,
    REJECTED: <XCircle className="w-3.5 h-3.5" />,
};

const BLOOD_GROUPS = ['A+', 'A-', 'B+', 'B-', 'O+', 'O-', 'AB+', 'AB-'];

const emptyForm = {
    name: '', description: '', address: '', city: '', state: 'Gujarat',
    date: '', startTime: '', endTime: '', totalSlots: 100,
    bloodGroupsNeeded: [], contactPhone: '', lat: '', lng: ''
};

const OrgDashboard = () => {
    const { user } = useAuthStore();
    const [activeSection, setActiveSection] = useState('create');
    const [camps, setCamps] = useState([]);
    const [isLoading, setIsLoading] = useState(false);
    const [form, setForm] = useState(emptyForm);

    const fetchMyCamps = async () => {
        try {
            const res = await api.get('/org/camps/my');
            if (res.data.status === 'success') setCamps(res.data.camps);
        } catch {
            toast.error('Could not load your camps.');
        }
    };

    useEffect(() => {
        fetchMyCamps();
    }, []);

    const toggleBloodGroup = (bg) => {
        setForm(f => ({
            ...f,
            bloodGroupsNeeded: f.bloodGroupsNeeded.includes(bg)
                ? f.bloodGroupsNeeded.filter(x => x !== bg)
                : [...f.bloodGroupsNeeded, bg]
        }));
    };

    const submitCamp = async (e) => {
        e.preventDefault();
        setIsLoading(true);
        try {
            await api.post('/org/camps', {
                ...form,
                bloodGroupsNeeded: form.bloodGroupsNeeded.join(','),
                lat: form.lat ? parseFloat(form.lat) : null,
                lng: form.lng ? parseFloat(form.lng) : null,
            });
            toast.success('Camp submitted for admin approval! Location automatically set based on city.');
            setForm(emptyForm);
            setActiveSection('my-camps');
            fetchMyCamps();
        } catch (err) {
            toast.error(err.response?.data?.message || 'Failed to submit camp.');
        } finally {
            setIsLoading(false);
        }
    };

    const tabVars = {
        hidden: { opacity: 0, y: 10 },
        visible: { opacity: 1, y: 0, transition: { duration: 0.3 } },
        exit: { opacity: 0, y: -10 }
    };

    const approvedCount = camps.filter(c => c.status === 'APPROVED').length;
    const pendingCount = camps.filter(c => c.status === 'PENDING').length;

    return (
        <div className="min-h-[calc(100vh-80px)] bg-gray-50 flex flex-col md:flex-row relative">
            <div className="absolute inset-0 pointer-events-none z-0 opacity-40" style={{ backgroundImage: 'radial-gradient(#e5e7eb 1px, transparent 1px)', backgroundSize: '20px 20px' }} />

            {/* Sidebar */}
            <motion.div initial={{ x: -50, opacity: 0 }} animate={{ x: 0, opacity: 1 }}
                className="w-full md:w-72 bg-gradient-to-b from-indigo-900 to-indigo-800 text-white flex flex-col z-10 md:min-h-[calc(100vh-80px)] border-r border-indigo-700/50 shadow-xl">
                <div className="p-8 hidden md:block">
                    <div className="flex items-center gap-3 mb-1">
                        <Building2 className="w-6 h-6 text-indigo-300" />
                        <h2 className="text-xl font-bold brand-font text-white/90">Org Dashboard</h2>
                    </div>
                    <p className="text-indigo-300 text-sm truncate">{user?.orgName || user?.name}</p>
                </div>

                <nav className="flex md:flex-col gap-2 p-4 md:p-5 overflow-x-auto">
                    {[
                        { id: 'overview', icon: Building2, label: 'Overview' },
                        { id: 'create', icon: Plus, label: 'Create Camp' },
                        { id: 'my-camps', icon: Calendar, label: 'My Camps' },
                    ].map(item => (
                        <button key={item.id} onClick={() => setActiveSection(item.id)}
                            className={`flex items-center gap-3 px-5 py-4 rounded-2xl transition-all font-medium whitespace-nowrap
                                ${activeSection === item.id
                                    ? 'bg-gradient-to-r from-indigo-500 to-blue-500 text-white shadow-lg'
                                    : 'text-indigo-200 hover:bg-white/5 hover:text-white'}`}>
                            <item.icon className="w-5 h-5" /> {item.label}
                        </button>
                    ))}
                </nav>
            </motion.div>

            {/* Content */}
            <div className="flex-grow p-6 md:p-12 z-10 relative overflow-hidden">
                <AnimatePresence mode="wait">
                    {/* OVERVIEW */}
                    {activeSection === 'overview' && (
                        <motion.div key="overview" variants={tabVars} initial="hidden" animate="visible" exit="exit" className="max-w-4xl mx-auto">
                            <h1 className="text-3xl md:text-4xl font-black text-gray-900 brand-font mb-2">
                                Welcome, {user?.orgName || user?.name}! ≡ƒÅÑ
                            </h1>
                            <p className="text-gray-500 mb-10">Manage your blood donation camps. Create new camps for admin approval.</p>

                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
                                {[
                                    { label: 'Total Camps', value: camps.length, color: 'text-indigo-600', border: 'border-indigo-200', bg: 'bg-indigo-50' },
                                    { label: 'Approved', value: approvedCount, color: 'text-green-600', border: 'border-green-200', bg: 'bg-green-50' },
                                    { label: 'Pending Review', value: pendingCount, color: 'text-yellow-600', border: 'border-yellow-200', bg: 'bg-yellow-50' },
                                ].map(stat => (
                                    <motion.div key={stat.label} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
                                        className={`bg-white/80 backdrop-blur-xl p-8 rounded-3xl shadow-sm border ${stat.border}`}>
                                        <div className={`w-10 h-10 ${stat.bg} rounded-2xl flex items-center justify-center mb-4 border ${stat.border}`}>
                                            <Calendar className={`w-5 h-5 ${stat.color}`} />
                                        </div>
                                        <p className="text-gray-400 text-xs uppercase font-bold tracking-widest">{stat.label}</p>
                                        <h2 className={`text-5xl font-black mt-2 brand-font ${stat.color}`}>{stat.value}</h2>
                                    </motion.div>
                                ))}
                            </div>

                            <div className="bg-white/60 backdrop-blur-xl p-8 rounded-3xl shadow-sm border border-gray-100">
                                <h3 className="font-bold text-gray-900 brand-font text-xl mb-6">Quick Actions</h3>
                                <div className="grid md:grid-cols-2 gap-4">
                                    <button onClick={() => setActiveSection('create')}
                                        className="p-6 bg-indigo-50 text-indigo-700 rounded-2xl border border-indigo-100 flex items-center gap-4 hover:bg-indigo-600 hover:text-white transition-all group text-left">
                                        <div className="w-12 h-12 bg-white/50 rounded-xl flex items-center justify-center group-hover:bg-white/20 shrink-0">
                                            <Plus className="w-6 h-6" />
                                        </div>
                                        <div>
                                            <div className="font-bold text-lg">Create New Camp</div>
                                            <div className="text-sm opacity-80 mt-0.5">Submit a camp for admin approval</div>
                                        </div>
                                    </button>
                                    <button onClick={() => setActiveSection('my-camps')}
                                        className="p-6 bg-gray-50 text-gray-700 rounded-2xl border border-gray-200 flex items-center gap-4 hover:bg-gray-900 hover:text-white transition-all group text-left">
                                        <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center group-hover:bg-white/20 shrink-0">
                                            <FileText className="w-6 h-6" />
                                        </div>
                                        <div>
                                            <div className="font-bold text-lg">View My Camps</div>
                                            <div className="text-sm opacity-80 mt-0.5">Track approval status</div>
                                        </div>
                                    </button>
                                </div>
                            </div>
                        </motion.div>
                    )}

                    {/* CREATE CAMP */}
                    {activeSection === 'create' && (
                        <motion.div key="create" variants={tabVars} initial="hidden" animate="visible" exit="exit" className="max-w-2xl">
                            <h2 className="text-3xl font-bold mb-2 text-gray-900 brand-font">Create Donation Camp</h2>
                            <p className="text-gray-500 mb-8">Fill in the details. Your camp will be reviewed and approved by the admin.</p>

                            <div className="bg-white/90 backdrop-blur-xl p-8 md:p-10 rounded-3xl shadow-xl border border-gray-100">
                                <form className="space-y-6" onSubmit={submitCamp}>
                                    {/* Camp Name */}
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 ml-1">Camp Name</label>
                                        <input required value={form.name} onChange={e => setForm({ ...form, name: e.target.value })}
                                            className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3.5 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all font-medium"
                                            placeholder="e.g. Ahmedabad Civil Blood Drive" />
                                    </div>

                                    {/* Description */}
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 ml-1">Description</label>
                                        <textarea value={form.description} onChange={e => setForm({ ...form, description: e.target.value })}
                                            rows={3}
                                            className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3.5 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all resize-none"
                                            placeholder="Brief description about the camp..." />
                                    </div>

                                    {/* Date & Times */}
                                    <div className="grid grid-cols-3 gap-4">
                                        <div>
                                            <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 ml-1">Date</label>
                                            <input required type="date" value={form.date} onChange={e => setForm({ ...form, date: e.target.value })}
                                                className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3.5 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all" />
                                        </div>
                                        <div>
                                            <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 ml-1">Start Time</label>
                                            <input required type="time" value={form.startTime} onChange={e => setForm({ ...form, startTime: e.target.value })}
                                                className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3.5 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all" />
                                        </div>
                                        <div>
                                            <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 ml-1">End Time</label>
                                            <input required type="time" value={form.endTime} onChange={e => setForm({ ...form, endTime: e.target.value })}
                                                className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3.5 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all" />
                                        </div>
                                    </div>

                                    {/* Address & City */}
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 ml-1">Full Address</label>
                                        <div className="relative">
                                            <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                                            <input required value={form.address} onChange={e => setForm({ ...form, address: e.target.value })}
                                                className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-12 pr-4 py-3.5 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all font-medium"
                                                placeholder="e.g. Civil Hospital, Asarwa, Ahmedabad" />
                                        </div>
                                    </div>

                                    <div className="grid grid-cols-2 gap-4">
                                        <div>
                                            <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 ml-1">City</label>
                                            <div className="relative">
                                                <input required value={form.city} onChange={e => setForm({ ...form, city: e.target.value })}
                                                    className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3.5 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all"
                                                    placeholder="e.g. Ahmedabad, Surat, Vadodara..." 
                                                    list="cities" />
                                                <datalist id="cities">
                                                    <option value="Ahmedabad" />
                                                    <option value="Surat" />
                                                    <option value="Vadodara" />
                                                    <option value="Rajkot" />
                                                    <option value="Gandhinagar" />
                                                    <option value="Bhavnagar" />
                                                    <option value="Jamnagar" />
                                                    <option value="Junagadh" />
                                                    <option value="Anand" />
                                                    <option value="Bharuch" />
                                                    <option value="Patan" />
                                                    <option value="Morbi" />
                                                    <option value="Mumbai" />
                                                    <option value="Delhi" />
                                                    <option value="Bangalore" />
                                                    <option value="Chennai" />
                                                    <option value="Pune" />
                                                </datalist>
                                                {form.city && (
                                                    <div className="absolute right-3 top-1/2 -translate-y-1/2">
                                                        <div className="flex items-center gap-1 text-xs">
                                                            <MapPin className="w-3 h-3 text-green-500" />
                                                            <span className="text-green-600 font-medium">Auto-located</span>
                                                        </div>
                                                    </div>
                                                )}
                                            </div>
                                            {form.city && (
                                                <p className="text-xs text-green-600 mt-1 flex items-center gap-1">
                                                    <span className="w-1.5 h-1.5 bg-green-500 rounded-full"></span>
                                                    Location will be automatically set on map for {form.city}
                                                </p>
                                            )}
                                        </div>
                                        <div>
                                            <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 ml-1">Total Slots</label>
                                            <div className="relative">
                                                <Users className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                                                <input type="number" min="10" value={form.totalSlots} onChange={e => setForm({ ...form, totalSlots: e.target.value })}
                                                    className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-12 pr-4 py-3.5 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all" />
                                            </div>
                                        </div>
                                    </div>

                                    {/* Contact */}
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 ml-1">Contact Phone</label>
                                        <div className="relative">
                                            <Phone className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                                            <input type="tel" value={form.contactPhone} onChange={e => setForm({ ...form, contactPhone: e.target.value })}
                                                className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-12 pr-4 py-3.5 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all"
                                                placeholder="+91 00000 00000" />
                                        </div>
                                    </div>

                                    {/* Blood Groups Needed */}
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-3 ml-1">Blood Groups Needed</label>
                                        <div className="flex flex-wrap gap-2">
                                            {BLOOD_GROUPS.map(bg => (
                                                <button type="button" key={bg} onClick={() => toggleBloodGroup(bg)}
                                                    className={`px-4 py-2 rounded-xl text-sm font-black border-2 transition-all ${form.bloodGroupsNeeded.includes(bg)
                                                        ? 'bg-red-600 text-white border-red-600 shadow-lg'
                                                        : 'bg-red-50 text-red-700 border-red-100 hover:border-red-300'}`}>
                                                    {bg}
                                                </button>
                                            ))}
                                        </div>
                                    </div>

                                    <button disabled={isLoading}
                                        className="w-full bg-gradient-to-r from-indigo-600 to-blue-600 hover:from-indigo-500 hover:to-blue-500 disabled:opacity-50 text-white font-bold py-4 rounded-xl transition-all shadow-lg hover:-translate-y-0.5 mt-2">
                                        {isLoading ? 'Submitting...' : 'Submit for Admin Approval'}
                                    </button>
                                </form>
                            </div>
                        </motion.div>
                    )}

                    {/* MY CAMPS */}
                    {activeSection === 'my-camps' && (
                        <motion.div key="my-camps" variants={tabVars} initial="hidden" animate="visible" exit="exit" className="max-w-5xl">
                            <h2 className="text-3xl font-bold mb-2 text-gray-900 brand-font">My Camps</h2>
                            <p className="text-gray-500 mb-8">Track the status of all your submitted donation camps.</p>

                            {camps.length === 0 ? (
                                <div className="bg-white/80 rounded-3xl border border-gray-100 p-20 text-center">
                                    <Calendar className="w-12 h-12 mx-auto mb-4 text-gray-300" />
                                    <h3 className="font-bold text-gray-500">No camps yet</h3>
                                    <p className="text-gray-400 text-sm mt-1">Create your first donation camp to get started.</p>
                                    <button onClick={() => setActiveSection('create')}
                                        className="mt-6 bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-indigo-700 transition-all inline-flex items-center gap-2">
                                        <Plus className="w-4 h-4" /> Create Camp
                                    </button>
                                </div>
                            ) : (
                                <div className="space-y-4">
                                    {camps.map(camp => (
                                        <motion.div key={camp.id} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
                                            className="bg-white/80 backdrop-blur-xl p-6 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-all">
                                            <div className="flex justify-between items-start flex-wrap gap-4">
                                                <div className="flex-grow">
                                                    <div className="flex items-center gap-3 flex-wrap mb-2">
                                                        <h3 className="font-black text-gray-900 text-lg brand-font">{camp.name}</h3>
                                                        <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-lg text-xs font-bold border ${STATUS_STYLES[camp.status]}`}>
                                                            {STATUS_ICONS[camp.status]} {camp.status}
                                                        </span>
                                                    </div>
                                                    <div className="flex flex-wrap gap-4 text-sm text-gray-500">
                                                        <span className="flex items-center gap-1.5"><Calendar className="w-4 h-4 text-indigo-400" />{(() => {
                                                            const d = new Date(camp.date);
                                                            return (camp.date && !isNaN(d.getTime())) ? d.toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' }) : 'TBA';
                                                        })()}</span>
                                                        <span className="flex items-center gap-1.5"><Clock className="w-4 h-4 text-indigo-400" />{camp.startTime} ΓÇô {camp.endTime}</span>
                                                        <span className="flex items-center gap-1.5"><MapPin className="w-4 h-4 text-indigo-400" />{camp.city}</span>
                                                        <span className="flex items-center gap-1.5"><Users className="w-4 h-4 text-indigo-400" />{camp.totalSlots} slots</span>
                                                    </div>
                                                    {camp.status === 'REJECTED' && camp.adminNote && (
                                                        <div className="mt-3 p-3 bg-red-50 rounded-lg border border-red-100 text-sm text-red-700">
                                                            <span className="font-bold">Admin note:</span> {camp.adminNote}
                                                        </div>
                                                    )}
                                                </div>
                                            </div>
                                        </motion.div>
                                    ))}
                                </div>
                            )}
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>
        </div>
    );
};

export default OrgDashboard;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Link, useNavigate } from 'react-router-dom';
import { Mail, Lock, HeartPulse, ArrowRight, User, Droplet, CalendarDays, Building2, Phone, MapPin, CheckCircle2 } from 'lucide-react';
import { useAuthStore } from '../context/authStore';

const ROLES = [
    { id: 'DONOR', label: 'User / Donor', desc: 'Donate blood or request blood for emergencies', color: 'red' },
    { id: 'ORGANIZATION', label: 'Organization', desc: 'Host blood donation camps in your area', color: 'indigo' },
];

const Register = () => {
    const [role, setRole] = useState('DONOR');
    const [formData, setFormData] = useState({
        name: '', email: '', password: '',
        bloodGroup: '', age: '',
        // Org-specific
        orgName: '', orgPhone: '', orgAddress: ''
    });
    const { register, isLoading } = useAuthStore();
    const navigate = useNavigate();

    const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });

    const handleRegister = async (e) => {
        e.preventDefault();
        const success = await register({ ...formData, role });
        if (success) {
            if (role === 'ORGANIZATION') {
                navigate('/org-dashboard');
            } else {
                navigate('/dashboard');
            }
        }
    };


    return (
        <div className="flex-grow flex items-center justify-center min-h-[calc(100vh-80px)] relative overflow-hidden bg-[var(--bg-primary)] py-12">
            {/* Premium Backdrop */}
            <div className="absolute inset-0 z-0">
                <img src="/images/sanctuary_bg.png" className="w-full h-full object-cover opacity-[0.03] scale-110 pointer-events-none" alt="" />
                <div className="absolute inset-0 bg-gradient-to-br from-[var(--accent)]/5 via-transparent to-transparent"></div>
            </div>

            <motion.div 
                animate={{ scale: [1, 1.1, 1], rotate: [0, -5, 0] }} 
                transition={{ repeat: Infinity, duration: 25, ease: "easeInOut" }}
                className="absolute top-[-10%] left-[-10%] w-[600px] h-[600px] bg-[var(--accent)] rounded-full mix-blend-multiply filter blur-[150px] opacity-[0.05] z-0" 
            />

            <div className="container mx-auto px-6 relative z-10 flex justify-center py-20">
                <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ duration: 0.8 }} className="w-full max-w-2xl">
                    <div className="bg-[var(--bg-secondary)] backdrop-blur-[40px] p-16 rounded-[4rem] shadow-[var(--shadow)] border border-[var(--border)] relative overflow-hidden">
                        <div className="text-center mb-12">
                            <div className="w-20 h-20 bg-[var(--bg-primary)] rounded-3xl flex items-center justify-center mx-auto mb-8 shadow-inner border border-[var(--border)]">
                                <HeartPulse className="text-[var(--accent)] w-10 h-10" />
                            </div>
                            <h2 className="text-4xl font-black text-[var(--text-primary)] brand-font mb-3 tracking-tight uppercase">New Recruit</h2>
                            <p className="text-[var(--text-muted)] text-xs font-black uppercase tracking-[0.3em]">Join the life-saving network.</p>
                        </div>

                        {/* Role Selector */}
                        <div className="mb-12">
                            <p className="text-[10px] font-black text-[var(--text-muted)] uppercase tracking-[0.3em] mb-4 ml-2">Choose your pathway</p>
                            <div className="grid grid-cols-2 gap-4">
                                {ROLES.map(r => (
                                    <button type="button" key={r.id} onClick={() => setRole(r.id)}
                                        className={`p-6 rounded-3xl border-2 text-left transition-all duration-300 relative overflow-hidden group ${role === r.id
                                            ? 'border-[var(--accent)] bg-[var(--accent)]/5'
                                            : 'border-[var(--border)] bg-[var(--bg-primary)] hover:border-gray-500'}`}>
                                        {role === r.id && <div className="absolute top-0 right-0 p-2"><CheckCircle2 className="w-4 h-4 text-[var(--accent)]" /></div>}
                                        <div className={`font-black text-xs mb-2 uppercase tracking-widest ${role === r.id ? 'text-[var(--text-primary)]' : 'text-[var(--text-muted)]'}`}>{r.label}</div>
                                        <div className="text-[var(--text-muted)] text-[10px] font-medium leading-relaxed opacity-70">{r.desc}</div>
                                    </button>
                                ))}
                            </div>
                        </div>

                        <form onSubmit={handleRegister} className="space-y-8">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                <div className="space-y-2 group/input">
                                    <label className="block text-[10px] font-black text-[var(--text-muted)] uppercase tracking-[0.2em] ml-2">
                                        {role === 'ORGANIZATION' ? 'Contact Person' : 'Full Name'}
                                    </label>
                                    <div className="relative">
                                        <div className="absolute left-6 top-1/2 -translate-y-1/2 text-[var(--text-muted)] group-focus-within/input:text-[var(--accent)] transition-colors"><User className="w-4 h-4" /></div>
                                        <input type="text" name="name" value={formData.name} onChange={handleChange} required className="w-full bg-[var(--bg-primary)] border border-[var(--border)] text-[var(--text-primary)] placeholder-gray-600 rounded-2xl pl-14 pr-6 py-4 focus:outline-none focus:ring-4 focus:ring-[var(--accent)]/10 focus:border-[var(--accent)] transition-all font-bold" placeholder="e.g. John Doe" />
                                    </div>
                                </div>

                                <div className="space-y-2 group/input">
                                    <label className="block text-[10px] font-black text-[var(--text-muted)] uppercase tracking-[0.2em] ml-2">Email Address</label>
                                    <div className="relative">
                                        <div className="absolute left-6 top-1/2 -translate-y-1/2 text-[var(--text-muted)] group-focus-within/input:text-[var(--accent)] transition-colors"><Mail className="w-4 h-4" /></div>
                                        <input type="email" name="email" value={formData.email} onChange={handleChange} required className="w-full bg-[var(--bg-primary)] border border-[var(--border)] text-[var(--text-primary)] placeholder-gray-600 rounded-2xl pl-14 pr-6 py-4 focus:outline-none focus:ring-4 focus:ring-[var(--accent)]/10 focus:border-[var(--accent)] transition-all font-bold" placeholder="email@example.com" />
                                    </div>
                                </div>
                            </div>

                            <AnimatePresence mode="wait">
                                {role === 'ORGANIZATION' ? (
                                    <motion.div key="org" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }} className="space-y-8">
                                        <div className="space-y-2 group/input">
                                            <label className="block text-[10px] font-black text-[var(--text-muted)] uppercase tracking-[0.2em] ml-2">Organization Name</label>
                                            <div className="relative">
                                                <div className="absolute left-6 top-1/2 -translate-y-1/2 text-[var(--text-muted)] group-focus-within/input:text-[var(--accent)] transition-colors"><Building2 className="w-4 h-4" /></div>
                                                <input type="text" name="orgName" value={formData.orgName} onChange={handleChange} required={role === 'ORGANIZATION'} className="w-full bg-[var(--bg-primary)] border border-[var(--border)] text-[var(--text-primary)] placeholder-gray-600 rounded-2xl pl-14 pr-6 py-4 focus:outline-none focus:ring-4 focus:ring-[var(--accent)]/10 focus:border-[var(--accent)] transition-all font-bold" placeholder="Organization Legal Name" />
                                            </div>
                                        </div>
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                            <div className="space-y-2 group/input">
                                                <label className="block text-[10px] font-black text-[var(--text-muted)] uppercase tracking-[0.2em] ml-2">Phone</label>
                                                <div className="relative">
                                                    <div className="absolute left-6 top-1/2 -translate-y-1/2 text-[var(--text-muted)] group-focus-within/input:text-[var(--accent)] transition-colors"><Phone className="w-4 h-4" /></div>
                                                    <input type="tel" name="orgPhone" value={formData.orgPhone} onChange={handleChange} className="w-full bg-[var(--bg-primary)] border border-[var(--border)] text-[var(--text-primary)] placeholder-gray-600 rounded-2xl pl-14 pr-6 py-4 focus:outline-none focus:ring-4 focus:ring-[var(--accent)]/10 focus:border-[var(--accent)] transition-all font-bold" placeholder="+91 ..." />
                                                </div>
                                            </div>
                                            <div className="space-y-2 group/input">
                                                <label className="block text-[10px] font-black text-[var(--text-muted)] uppercase tracking-[0.2em] ml-2">City</label>
                                                <div className="relative">
                                                    <div className="absolute left-6 top-1/2 -translate-y-1/2 text-[var(--text-muted)] group-focus-within/input:text-[var(--accent)] transition-colors"><MapPin className="w-4 h-4" /></div>
                                                    <input type="text" name="orgAddress" value={formData.orgAddress} onChange={handleChange} className="w-full bg-[var(--bg-primary)] border border-[var(--border)] text-[var(--text-primary)] placeholder-gray-600 rounded-2xl pl-14 pr-6 py-4 focus:outline-none focus:ring-4 focus:ring-[var(--accent)]/10 focus:border-[var(--accent)] transition-all font-bold" placeholder="City Location" />
                                                </div>
                                            </div>
                                        </div>
                                    </motion.div>
                                ) : (
                                    <motion.div key="donor" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }} className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                        <div className="space-y-2 group/input">
                                            <label className="block text-[10px] font-black text-[var(--text-muted)] uppercase tracking-[0.2em] ml-2">Blood Group</label>
                                            <div className="relative">
                                                <div className="absolute left-6 top-1/2 -translate-y-1/2 text-[var(--text-muted)] group-focus-within/input:text-[var(--accent)] transition-colors"><Droplet className="w-4 h-4" /></div>
                                                <select name="bloodGroup" value={formData.bloodGroup} onChange={handleChange} required={role === 'DONOR'}
                                                    className="w-full bg-[var(--bg-primary)] border border-[var(--border)] text-[var(--text-primary)] rounded-2xl pl-14 pr-6 py-4 focus:outline-none focus:ring-4 focus:ring-[var(--accent)]/10 focus:border-[var(--accent)] transition-all font-bold appearance-none">
                                                    <option value="" disabled>Select</option>
                                                    {['A+', 'A-', 'B+', 'B-', 'O+', 'O-', 'AB+', 'AB-'].map(bg => <option key={bg} value={bg}>{bg}</option>)}
                                                </select>
                                            </div>
                                        </div>
                                        <div className="space-y-2 group/input">
                                            <label className="block text-[10px] font-black text-[var(--text-muted)] uppercase tracking-[0.2em] ml-2">Age</label>
                                            <div className="relative">
                                                <div className="absolute left-6 top-1/2 -translate-y-1/2 text-[var(--text-muted)] group-focus-within/input:text-[var(--accent)] transition-colors"><CalendarDays className="w-4 h-4" /></div>
                                                <input type="number" name="age" min="18" max="65" value={formData.age} onChange={handleChange} required={role === 'DONOR'}
                                                    className="w-full bg-[var(--bg-primary)] border border-[var(--border)] text-[var(--text-primary)] placeholder-gray-600 rounded-2xl pl-14 pr-6 py-4 focus:outline-none focus:ring-4 focus:ring-[var(--accent)]/10 focus:border-[var(--accent)] transition-all font-bold" placeholder="18ΓÇô65" />
                                            </div>
                                        </div>
                                    </motion.div>
                                )}
                            </AnimatePresence>

                            <div className="space-y-2 group/input">
                                <label className="block text-[10px] font-black text-[var(--text-muted)] uppercase tracking-[0.2em] ml-2">Secure Keycode (Password)</label>
                                <div className="relative">
                                    <div className="absolute left-6 top-1/2 -translate-y-1/2 text-[var(--text-muted)] group-focus-within/input:text-[var(--accent)] transition-colors"><Lock className="w-4 h-4" /></div>
                                    <input type="password" name="password" minLength="6" value={formData.password} onChange={handleChange} required className="w-full bg-[var(--bg-primary)] border border-[var(--border)] text-[var(--text-primary)] placeholder-gray-600 rounded-2xl pl-14 pr-6 py-4 focus:outline-none focus:ring-4 focus:ring-[var(--accent)]/10 focus:border-[var(--accent)] transition-all font-bold" placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó" />
                                </div>
                            </div>

                            <button type="submit" disabled={isLoading}
                                className="w-full bg-slate-950 text-white font-black py-6 rounded-2xl transition-all shadow-2xl hover:shadow-black/40 hover:-translate-y-1 active:translate-y-0 flex items-center justify-center gap-3 group/btn disabled:opacity-70 disabled:cursor-not-allowed mt-12 tracking-[0.2em] uppercase text-sm border border-white/5">
                                {isLoading ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <>Complete Enrollment <ArrowRight className="w-5 h-5 group-hover/btn:translate-x-2 transition-transform" /></>}
                            </button>
                        </form>

                        <div className="mt-12 text-center text-[var(--text-muted)] text-xs font-bold uppercase tracking-widest">
                            Already enlisted? <Link to="/login" className="text-[var(--accent)] font-black hover:underline underline-offset-4">Log in</Link>
                        </div>
                    </div>
                </motion.div>
            </div>
        </div>
    );
};

export default Register;
